require.config({"config": {
        "text":{"Magento_PaymentServicesPaypal/template/payment/fastlane.html":"<!--\n/**\n * Copyright \u00a9 Magento, Inc. All rights reserved.\n * See COPYING.txt for license details.\n */\n-->\n<div class=\"payment-method card-grid\" css=\"'_active': (getCode() == isChecked())\">\n    <div class=\"payment-method-title field choice flex-center\">\n        <input type=\"radio\"\n               name=\"payment[method]\"\n               class=\"radio\"\n               attr=\"'id': getCode()\"\n               ko-value=\"getCode()\"\n               ko-checked=\"isChecked\"\n               click=\"selectPaymentMethod\"\n               visible=\"isRadioButtonVisible()\">\n        <label data-bind=\"attr: {'for': getCode()}\" class=\"label flex-center\">\n            <img class=\"payment-type-icon\" data-bind=\"attr: { src: paymentTypeIconUrl, alt: paymentTypeIconTitle }\" />\n            <span data-bind=\"text: getTitle()\"></span>\n        </label>\n    </div>\n    <div id=\"checkout-form\" class=\"payment-method-content\">\n        <!-- ko foreach: getRegion('messages') -->\n        <!-- ko template: getTemplate() --><!-- /ko -->\n        <!--/ko-->\n        <div id=\"payment-services-paypal-fastlane\" afterRender=\"afterRender\"></div>\n        <div class=\"checkout-agreements-block\">\n            <!-- ko foreach: $parent.getRegion('before-place-order') -->\n            <!-- ko template: getTemplate() --><!-- /ko -->\n            <!--/ko-->\n        </div>\n        <div class=\"actions-toolbar\">\n            <div class=\"primary\">\n                <button id=\"card-field-submit-button\" class=\"action primary checkout\" type=\"button\" data-bind=\"css: {'paypal-disabled': !isPlaceOrderActionAllowed()}, click: onClick\">\n                    <span data-bind=\"i18n: 'Place Order'\"></span>\n                </button>\n            </div>\n        </div>\n    </div>\n</div>\n"}
}});
